// CSV file validation and metadata extraction
const fs = require('fs');
const path = require('path');
const csv = require('csv-parser');

const filePath = inputs.file_path;
const fileName = path.basename(filePath);

try {
  // Check file size
  const stats = fs.statSync(filePath);
  const fileSizeMB = stats.size / (1024 * 1024);

  if (fileSizeMB > inputs.max_file_size_mb) {
    throw new Error(`File size ${fileSizeMB.toFixed(2)}MB exceeds maximum ${inputs.max_file_size_mb}MB`);
  }

  // Quick header validation
  const firstLine = fs.readFileSync(filePath, 'utf8').split('
')[0];
  const headers = firstLine.split(',').map(h => h.trim().replace(/["']/g, ''));

  // Validate required columns
  const requiredColumns = inputs.required_columns || [];
  const missingColumns = requiredColumns.filter(col => !headers.includes(col));

  if (missingColumns.length > 0) {
    throw new Error(`Missing required columns: ${missingColumns.join(', ')}`);
  }

  // Estimate row count (approximate)
  const sampleLines = fs.readFileSync(filePath, 'utf8').split('
').slice(0, 100);
  const avgLineLength = sampleLines.reduce((sum, line) => sum + line.length, 0) / sampleLines.length;
  const estimatedRows = Math.floor(stats.size / avgLineLength) - 1; // -1 for header

  return {
    validation_status: 'valid',
    file_path: filePath,
    file_name: fileName,
    file_size_mb: fileSizeMB,
    estimated_rows: estimatedRows,
    headers: headers,
    column_count: headers.length,
    processing_batch_size: Math.min(inputs.batch_size, Math.ceil(estimatedRows / 10))
  };

} catch (error) {
  return {
    validation_status: 'invalid',
    file_path: filePath,
    file_name: fileName,
    error_message: error.message,
    should_skip: true
  };
}

// Advanced CSV batch processing with streaming
const fs = require('fs');
const csv = require('csv-parser');
const { Transform } = require('stream');

const filePath = inputs.file_path;
const batchSize = inputs.processing_batch_size;
const transformationRules = inputs.transformation_rules || [];

let processedRows = [];
let errorRows = [];
let totalProcessed = 0;
let currentBatch = [];

// Custom transformation stream
const transformStream = new Transform({
  objectMode: true,
  transform(row, encoding, callback) {
    try {
      let transformedRow = { ...row };

      // Apply transformation rules
      for (const rule of transformationRules) {
        switch (rule.type) {
          case 'rename_column':
            if (transformedRow[rule.from]) {
              transformedRow[rule.to] = transformedRow[rule.from];
              delete transformedRow[rule.from];
            }
            break;

          case 'format_date':
            if (transformedRow[rule.column]) {
              const date = new Date(transformedRow[rule.column]);
              if (!isNaN(date.getTime())) {
                transformedRow[rule.column] = date.toISOString();
              } else {
                throw new Error(`Invalid date format in ${rule.column}: ${transformedRow[rule.column]}`);
              }
            }
            break;

          case 'normalize_text':
            if (transformedRow[rule.column]) {
              transformedRow[rule.column] = transformedRow[rule.column]
                .toString()
                .toLowerCase()
                .trim()
                .replace(/\s+/g, ' ');
            }
            break;

          case 'validate_email':
            if (transformedRow[rule.column]) {
              const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
              if (!emailRegex.test(transformedRow[rule.column])) {
                throw new Error(`Invalid email format: ${transformedRow[rule.column]}`);
              }
            }
            break;

          case 'calculate_field':
            transformedRow[rule.target_column] = eval(rule.expression.replace(/\{([^}]+)\}/g, (match, field) => {
              return transformedRow[field] || '0';
            }));
            break;
        }
      }

      // Add metadata
      transformedRow._row_number = totalProcessed + 1;
      transformedRow._processed_at = new Date().toISOString();
      transformedRow._source_file = inputs.file_name;

      currentBatch.push(transformedRow);
      totalProcessed++;

      // Process batch when full
      if (currentBatch.length >= batchSize) {
        processedRows.push(...currentBatch);
        currentBatch = [];
      }

      callback();

    } catch (error) {
      errorRows.push({
        row_number: totalProcessed + 1,
        original_data: row,
        error_message: error.message,
        error_timestamp: new Date().toISOString()
      });

      totalProcessed++;
      callback();
    }
  }
});

return new Promise((resolve, reject) => {
  const stream = fs.createReadStream(filePath)
    .pipe(csv())
    .pipe(transformStream);

  stream.on('end', () => {
    // Process remaining batch
    if (currentBatch.length > 0) {
      processedRows.push(...currentBatch);
    }

    const processingStats = {
      total_rows_processed: totalProcessed,
      successful_rows: processedRows.length,
      error_rows: errorRows.length,
      success_rate: ((processedRows.length / totalProcessed) * 100).toFixed(2),
      processing_time_start: new Date().toISOString()
    };

    resolve({
      processed_data: processedRows,
      error_data: errorRows,
      processing_stats: processingStats
    });
  });

  stream.on('error', reject);
});

// Comprehensive data quality analysis
const processedData = inputs.processed_data;
const errorData = inputs.error_data;

if (processedData.length === 0) {
  return {
    quality_report: {
      overall_score: 0,
      total_records: 0,
      quality_issues: ['No data processed successfully']
    }
  };
}

// Analyze data completeness
const headers = Object.keys(processedData[0]).filter(key => !key.startsWith('_'));
const completenessAnalysis = {};
const duplicateAnalysis = {};
const valueDistribution = {};

for (const header of headers) {
  const values = processedData.map(row => row[header]);
  const nonEmptyValues = values.filter(val => val !== null && val !== undefined && val !== '');

  completenessAnalysis[header] = {
    total_values: values.length,
    non_empty_values: nonEmptyValues.length,
    completeness_percentage: ((nonEmptyValues.length / values.length) * 100).toFixed(2),
    empty_count: values.length - nonEmptyValues.length
  };

  // Value distribution analysis
  const uniqueValues = [...new Set(nonEmptyValues)];
  valueDistribution[header] = {
    unique_count: uniqueValues.length,
    uniqueness_percentage: ((uniqueValues.length / nonEmptyValues.length) * 100).toFixed(2),
    most_common: nonEmptyValues.reduce((acc, val) => {
      acc[val] = (acc[val] || 0) + 1;
      return acc;
    }, {})
  };
}

// Detect potential duplicates
const duplicateMap = {};
processedData.forEach((row, index) => {
  const key = headers.map(h => row[h]).join('|');
  if (duplicateMap[key]) {
    duplicateMap[key].push(index);
  } else {
    duplicateMap[key] = [index];
  }
});

const duplicateGroups = Object.values(duplicateMap).filter(group => group.length > 1);
const duplicateCount = duplicateGroups.reduce((sum, group) => sum + group.length - 1, 0);

// Calculate overall quality score
const avgCompleteness = Object.values(completenessAnalysis)
  .reduce((sum, analysis) => sum + parseFloat(analysis.completeness_percentage), 0) / headers.length;

const errorRate = (errorData.length / (processedData.length + errorData.length)) * 100;
const duplicateRate = (duplicateCount / processedData.length) * 100;

const qualityScore = Math.max(0, Math.min(100, 
  avgCompleteness * 0.4 +  // 40% weight on completeness
  (100 - errorRate) * 0.3 +  // 30% weight on error rate
  (100 - duplicateRate) * 0.2 +  // 20% weight on duplicate rate
  75 * 0.1  // 10% base score
));

const qualityIssues = [];
if (avgCompleteness < 80) qualityIssues.push(`Low data completeness: ${avgCompleteness.toFixed(2)}%`);
if (errorRate > 5) qualityIssues.push(`High error rate: ${errorRate.toFixed(2)}%`);
if (duplicateRate > 10) qualityIssues.push(`High duplicate rate: ${duplicateRate.toFixed(2)}%`);

return {
  quality_report: {
    overall_score: Math.round(qualityScore),
    total_records: processedData.length,
    error_records: errorData.length,
    duplicate_records: duplicateCount,
    avg_completeness: Math.round(avgCompleteness),
    error_rate: Math.round(errorRate * 100) / 100,
    duplicate_rate: Math.round(duplicateRate * 100) / 100,
    completeness_analysis: completenessAnalysis,
    value_distribution: valueDistribution,
    quality_issues: qualityIssues,
    duplicate_groups: duplicateGroups.slice(0, 10) // First 10 duplicate groups
  }
};

